SELECT CASE WHEN EXISTS (
    SELECT 1 FROM goals g
    WHERE g.id = #{id}
      AND (
          g.user_id = #{userId}
          OR g.is_public = TRUE
          OR EXISTS (SELECT 1 FROM goal_members m WHERE m.goal_id = g.id AND m.user_id = #{userId})
      )
) THEN 1 ELSE 0 END

SELECT CASE WHEN EXISTS (
    SELECT 1 FROM goals WHERE id = #{id} AND user_id = #{userId}
) THEN 1 ELSE 0 END
